function isIsomorphic(s, t) {
    if (s.length !== t.length) return false;

    const mapST = {};
    const mapTS = {};

    for (let i = 0; i < s.length; i++) {
        const c1 = s[i];
        const c2 = t[i];

        // Check mapping s -> t
        if (mapST[c1] !== undefined) {
            if (mapST[c1] !== c2) return false;
        } else {
            mapST[c1] = c2;
        }

        // Check mapping t -> s
        if (mapTS[c2] !== undefined) {
            if (mapTS[c2] !== c1) return false;
        } else {
            mapTS[c2] = c1;
        }
    }

    return true;
}
